var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`당신도, 나도. 그리고 모두.`,JPN:`貴方も私も。そしてすべて。`,ENG:`You, me, and everyone else.`,TWN:`貴方も私も。そしてすべて。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`여기 있는 이유가 있어.`,JPN:`ここにいる訳がある。`,ENG:`There is a reason why we are all here.`,TWN:`ここにいる訳がある。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`싫다고 해서 하나씩 밀어내게 되면, 세상은 하나밖에 남지 않아.`,JPN:`嫌だといってひとつずつ除いていったら、世界にはひとつしか残らない。`,ENG:`Pushing people away because you hate them will eventually make you alone in this world.`,TWN:`嫌だといってひとつずつ除いていったら、世界にはひとつしか残らない。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`당신도, 나도. 그리고 다른 누구도.`,JPN:`貴方も私も。そして他の誰も。`,ENG:`You, me, and everyone else.`,TWN:`貴方も私も。そして他の誰も。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`그런 세상에 남게 되는 건 바라지 않아.`,JPN:`そんな世界、残りたくなんかない。`,ENG:`No one wants to be left alone like that.`,TWN:`そんな世界、残りたくなんかない。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`하지만 어려운 말은 몰라. 말로는 전할 수 없어.`,JPN:`でも、言葉では伝えられないことが、きっとある。`,ENG:`I don't know any fancy words. It's not something I can explain.`,TWN:`でも、言葉では伝えられないことが、きっとある。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`싸움을 통해서 전해질 수 있다면, 싸울 거야.`,JPN:`もしも……それが戦いで伝えられるなら、戦う。`,ENG:`If fighting will convey it, I will fight.`,TWN:`もしも……それが戦いで伝えられるなら、戦う。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RAM_COLLABO_NULL_NULL`,text:{KOREA:`그렇게 해서라도…… 나는.`,JPN:`そうしてでも……私は。`,ENG:`Whatever it takes... I...`,TWN:`そうしてでも……私は。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAM_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};